+export function createDeferred(world: World): DeferredCommandBuffer {
+    return {
+        spawn(...traits) {
+            // Allocate now so a deferred spawn can be used as a relation target. It remains
+            // otherwise invisible to the command buffer until its queued traits are applied.
+            const entity = createEntity(world);
+            state(world).spawned.add(entity);
+            push(world, { type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) {
+            push(world, { type: 'destroy', entity });
+        },
+        add(entity, ...traits) {
+            push(world, { type: 'add', entity, traits });
+        },
+        remove(entity, ...traits) {
+            push(world, { type: 'remove', entity, traits });
+        },
+        addExclusive(entity, pair) {
+            push(world, { type: 'addExclusive', entity, pair });
+        },
+        flush() {
+            flushDeferred(world);
+        },
+    };
+}
+
+export function hasPendingCommands(world: World, entity: Entity) {
+    return !state(world).flushing && commands(world).some((command) => command.entity === entity);
+}
+
+export function beginDeferredScope(world: World) {
+    state(world).buffers.push([]);
+}
+
+export function endDeferredScope(world: World) {
+    const deferred = state(world);
+    const buffer = deferred.buffers.pop()!;
+    flushBuffer(world, buffer);
+}
+
+export function flushDeferred(world: World) {
+    const deferred = state(world);
+    // A flush applies every pending scope in command order. New commands produced by
+    // subscriptions are deliberately left in the root buffer for the next flush.
+    while (deferred.buffers.some((buffer) => buffer.length)) {
+        for (const buffer of deferred.buffers) {
+            if (buffer.length) flushBuffer(world, buffer.splice(0));
+        }
+    }
+}
+
+function flushBuffer(world: World, buffer: DeferredCommand[]) {
+    if (!buffer.length) return;
+    const deferred = state(world);
+    deferred.flushing = true;
+    try {
+        for (const command of buffer) {
+            if (command.type === 'spawn') {
+                if (world.has(command.entity)) addTrait(world, command.entity, ...command.traits);
+                continue;
+            }
+            if (command.entity === world[$internal].worldEntity && command.type === 'destroy') {
+                throw new Error('Koota: The world entity cannot be destroyed through a deferred command.');
+            }
+            // Destruction can cascade. Subsequent commands targeting a dead entity are no-ops.
+            if (!world.has(command.entity)) continue;
+            if (command.type === 'destroy') destroyEntity(world, command.entity);
+            else if (command.type === 'add') addTrait(world, command.entity, ...command.traits);
+            else if (command.type === 'remove') removeTrait(world, command.entity, ...command.traits);
+            else if (command.type === 'addExclusive') {
+                const pair = command.pair;
+                const relation = pair[$internal].relation;
+                removeTrait(world, command.entity, relation('*'));
+                if (pair[$internal].target !== '*') addTrait(world, command.entity, pair);
+            }
+        }
+    } finally {
